O ResizableTable em `src/components/ResizableTable.tsx` implementa:

**Wrapper genérico tipado:**
```tsx
export function ResizableTable<T extends object>({
  columns,
  storageKey,
  ...restProps
}: ResizableTableProps<T>) {
  const [colWidths, setColWidths] = useState<Record<string, number>>(() =>
    typeof window !== 'undefined' ? loadWidths(storageKey) : {}
  );

  if (!columns) return <Table<T> {...restProps} columns={undefined} />;

  const mergedColumns = columns.map((col, i) => ({
    ...col,
    width: colWidths[col.key as string] || col.width,
    onHeaderCell: () => ({
      width: colWidths[col.key as string] || col.width,
      onResize: handleResize(col.key as string),
      onResizeStop: () => saveWidths(storageKey, colWidths),
    }),
  }));

  return (
    <Table<T>
      {...restProps}
      columns={mergedColumns}
      components={{
        header: { cell: ResizableTitle },
      }}
    />
  );
}
```

**localStorage com guard SSR:**
```tsx
function loadWidths(key: string): Record<string, number> {
  if (typeof window === 'undefined') return {};
  try {
    return JSON.parse(localStorage.getItem(`table_widths_${key}`) || '{}');
  } catch { return {}; }
}

function saveWidths(key: string, widths: Record<string, number>) {
  if (typeof window === 'undefined') return;
  try {
    localStorage.setItem(`table_widths_${key}`, JSON.stringify(widths));
  } catch { /* quota exceeded */ }
}
```

